END IF;
--*** MODIFICADO: Fin de la unificación (Validaciones y variables de control movidas arriba)
SET CHRHORA = REPLACE(
        REPLACE(CAST(CURRENT TIME AS VARCHAR(8)), ':', ''),
        '.',
        ''
    );
--** Obtener numero seguridad interno 
SELECT NEXTVAL FOR BLHSRVLIB.SECTRANSE INTO NUMNUMEROSEGURIDAD
FROM SYSIBM.SYSDUMMY1;
--*** MODIFICADO: Bloque redundante consolidado arriba
SET INTSINREGISTROS = 0;
--*** MODIFICADO: Bloque redundante eliminado (Ya procesado arriba)
END IF;
--** Se lleva el conteo de total de facturas por grupo 
SET INTTOTALFACT = INTTOTALFACT + 1;
IF CHRPROSEGUIR = 'S' THEN
SET DECTCCOMPRA = 0;
SET DECTCVENTA = 0;
SET NUMTASADECOMPRA = 0;
SET NUMTASADEVENTA = 0;
IF CHRMONEDACTAPAGADOR <> MONEDAFACTURA THEN IF CHRMONEDACTAPAGADOR = CHRMONCTAPAGADOR
AND MONEDAFACTURA = CHRMONFACTPROVEEDOR
AND CHRMONEDACTABENEFICIARIO = CHRMONCTAPROVEEDOR THEN
SET DECMONTODEBITOTEMP = ROUND (MONTO * DECTCUSDOFICIAL, 2);
SET DECMONTOCREDITOTEMP = DECMONTODEBITOTEMP;
SET DECTCVENTA = DECTCUSDOFICIAL;
SET NUMTASADEVENTA = DECTCVENTA;
SET INTOPCIONTC = 0;
ELSEIF CHRMONEDACTAPAGADOR = 'LPS' THEN IF MONEDAFACTURA = 'USD' THEN
SET DECTCCOMPRA = DECTCUSDCOMPRA;
SET DECTCVENTA = DECTCUSDVENTA;
SET INTOPCIONTC = 1;
ELSE
SET DECTCVENTA = DECTCEURVENTA;
SET INTOPCIONTC = 1;
END IF;
ELSEIF CHRMONEDACTAPAGADOR = 'USD' THEN IF MONEDAFACTURA <> CHRMONEDABASE THEN
SET DECTCCOMPRA = DECTCUSDCOMPRA;
SET DECTCVENTA = DECTCEURVENTA;
SET INTOPCIONTC = 1;
ELSE
SET DECTCCOMPRA = DECTCUSDCOMPRA;
SET DECTCVENTA = DECTCUSDVENTA;
SET INTOPCIONTC = 1;
END IF;
ELSEIF CHRMONEDACTAPAGADOR = 'EUR' THEN IF MONEDAFACTURA <> CHRMONEDABASE THEN
SET DECTCCOMPRA = DECTCEURCOMPRA;
SET DECTCVENTA = DECTCUSDVENTA;
SET INTOPCIONTC = 1;
ELSE
SET DECTCCOMPRA = DECTCEURCOMPRA;
SET DECTCVENTA = DECTCEURVENTA;
SET INTOPCIONTC = 1;
END IF;
END IF;
SET NUMUSUARIO = CIFPAGADOR;
SET DECMONTO = MONTO;
SET CHRCODMONEDA = MONEDAFACTURA;
IF INTOPCIONTC = 1 THEN
SET DECMONTOCREDITOTEMP = MONTO;
SET INTSINREGISTROS = 0;
OPEN CURTASAINVERTIDO;
FETCH CURTASAINVERTIDO INTO NUMLINEA,
NUMMONTOTRANSFERIDO,
CHRMONEDAORIGEN,
CHROPERACION,
NUMTASA,
NUMMONTOCONVERTIDO,
CHRMONEDADESTINO,
NUMTASANEGOCIADAEXCEDIDA,
CHRTIPOTASAUTILIZADA;
WHILE INTSINREGISTROS = 0 DO IF CHROPERACION = 'COMPRA' THEN IF CHRMONEDADESTINO = CHRMONEDABASE THEN
SET CHRMONEDACOMPRADA = CHRMONEDAORIGEN;
ELSE
SET CHRMONEDACOMPRADA = CHRMONEDADESTINO;
END IF;
SET NUMMONTOCOMPRADO = NUMMONTOTRANSFERIDO;
SET CHRWORKCOMPRA = 'C';
SET NUMTASADECOMPRA = NUMTASA;
SET NUMTASANEGOCIADAEXCEDIDACOMPRA = NUMTASANEGOCIADAEXCEDIDA;
SET CHRTIPOTASAUTILIZADOCOMPRA = CHRTIPOTASAUTILIZADA;
SET DECMONTODEBITOTEMP = NUMMONTOTRANSFERIDO;
ELSE IF CHRMONEDADESTINO = CHRMONEDABASE THEN
SET CHRMONEDAVENDIDA = CHRMONEDAORIGEN;
ELSE
SET CHRMONEDAVENDIDA = CHRMONEDADESTINO;
END IF;
SET NUMMONTOVENDIDO = NUMMONTOCONVERTIDO;
SET CHRWORKVENTA = 'V';
SET NUMTASADEVENTA = NUMTASA;
SET NUMTASANEGOCIADAEXCEDIDAVENTA = NUMTASANEGOCIADAEXCEDIDA;
SET CHRTIPOTASAUTILIZADOVENTA = CHRTIPOTASAUTILIZADA;
SET DECMONTODEBITOTEMP = NUMMONTOTRANSFERIDO;
END IF;
FETCH CURTASAINVERTIDO INTO NUMLINEA,
NUMMONTOTRANSFERIDO,
CHRMONEDAORIGEN,
CHROPERACION,
NUMTASA,
NUMMONTOCONVERTIDO,
CHRMONEDADESTINO,
NUMTASANEGOCIADAEXCEDIDA,
CHRTIPOTASAUTILIZADA;
END WHILE;
CLOSE CURTASAINVERTIDO;
ELSEIF INTOPCIONTC = 2 THEN
SET DECMONTOCREDITOTEMP = MONTO;
SET INTSINREGISTROS = 0;
OPEN CURTASANORMAL;
FETCH CURTASANORMAL INTO NUMLINEA,
NUMMONTOTRANSFERIDO,
CHRMONEDAORIGEN,
CHROPERACION,
NUMTASA,
NUMMONTOCONVERTIDO,
CHRMONEDADESTINO,
NUMTASANEGOCIADAEXCEDIDA,
CHRTIPOTASAUTILIZADA;
WHILE INTSINREGISTROS = 0 DO IF CHROPERACION = 'COMPRA' THEN IF CHRMONEDADESTINO = CHRMONEDABASE THEN
SET CHRMONEDACOMPRADA = CHRMONEDAORIGEN;
ELSE
SET CHRMONEDACOMPRADA = CHRMONEDADESTINO;
END IF;
SET NUMMONTOCOMPRADO = NUMMONTOTRANSFERIDO;
SET CHRWORKCOMPRA = 'C';
SET NUMTASADECOMPRA = NUMTASA;
SET NUMTASANEGOCIADAEXCEDIDACOMPRA = NUMTASANEGOCIADAEXCEDIDA;
SET CHRTIPOTASAUTILIZADOCOMPRA = CHRTIPOTASAUTILIZADA;
ELSE IF CHRMONEDADESTINO = CHRMONEDABASE THEN
SET CHRMONEDAVENDIDA = CHRMONEDAORIGEN;
ELSE
SET CHRMONEDAVENDIDA = CHRMONEDADESTINO;
END IF;
SET NUMMONTOVENDIDO = NUMMONTOCONVERTIDO;
SET CHRWORKVENTA = 'V';
SET NUMTASADEVENTA = NUMTASA;
SET NUMTASANEGOCIADAEXCEDIDAVENTA = NUMTASANEGOCIADAEXCEDIDA;
SET CHRTIPOTASAUTILIZADOVENTA = CHRTIPOTASAUTILIZADA;
SET DECMONTODEBITOTEMP = NUMMONTOCONVERTIDO;
END IF;
FETCH CURTASANORMAL INTO NUMLINEA,
NUMMONTOTRANSFERIDO,
CHRMONEDAORIGEN,
CHROPERACION,
NUMTASA,
NUMMONTOCONVERTIDO,
CHRMONEDADESTINO,
NUMTASANEGOCIADAEXCEDIDA,
CHRTIPOTASAUTILIZADA;
END WHILE;
CLOSE CURTASANORMAL;
END IF;
ELSE
SET DECMONTODEBITOTEMP = MONTO;
SET DECMONTOCREDITOTEMP = MONTO;
END IF;
SET NUMSALDODISPONIBLECUENTA = BLHSRVLIB.FN_SE_SEL_SALDOCUENTA (CTAPAGADOR);
IF NUMSALDODISPONIBLECUENTA >= DECMONTODEBITOTEMP THEN IF NUMTIPO = 1 THEN --** Se actualiza saldo de la cuenta pagador						 
/*CALL BLHSRVLIB . SP_SE_UPD_SALDODISPONIBLECUENTA ( CTAPAGADOR , DECMONTODEBITOTEMP , 'DB' , INTTIPORESULTADO , VARMENSAJERESULTADO ) ;    
 
 INSERT INTO SESSION . PGLOGPROCESOTMP ( FECHAINSERCION , NUMEROGRUPO , CODTRANSACCION , MONTODEBITARCTA , SALDOCTADEBITAR , TCCOMPRA , TCVENTA , MENSAJEPROCESO )    
 VALUES ( CURRENT TIMESTAMP , NUMNUMEROSEGURIDAD , NUMIDUNICOFACTURA , DECMONTODEBITOTEMP , NUMSALDODISPONIBLECUENTA , NUMTASADECOMPRA , NUMTASADEVENTA , 'SP_SE_UPD_SaldoDisponibleCuenta: ' || INTTIPORESULTADO || ' ' || VARMENSAJERESULTADO || ' ' || CHRPROSEGUIR ) ;    
 
 IF INTTIPORESULTADO <> 0 THEN    
 SET CHRPROSEGUIR = 'N' ;    
 END IF ;*/
IF CHRPROSEGUIR = 'S' THEN --** Se obtiene la fecha y hora actual. 
SELECT TIMESTAMP (
        DATE (
            CAST (CNTRDY + 2000 AS CHAR (4)) || '-' || CNTRDM || '-' || CNTRDD
        ),
        CURRENT TIME
    ) INTO TIMFECHAACTUAL
FROM BLHSRVLIB.A_CNTRLCNT;
--INSERT INTO SESSION . PGLOGPROCESOTMP ( FECHAINSERCION , NUMEROGRUPO , CODTRANSACCION , MONTODEBITARCTA , SALDOCTADEBITAR , TCCOMPRA , TCVENTA , MENSAJEPROCESO ) 
--VALUES ( CURRENT TIMESTAMP , NUMNUMEROSEGURIDAD , NUMIDUNICOFACTURA , DECMONTODEBITOTEMP , NUMSALDODISPONIBLECUENTA , NUMTASADECOMPRA , NUMTASADEVENTA , 'Despues obtener fecha: ' || COALESCE(INTTIPORESULTADO, '') || ' ' || COALESCE(VARMENSAJERESULTADO, '') || ' ' || COALESCE(CHRPROSEGUIR, '') ) ; 
UPDATE BLHCYFILES.TB_SE_TRN_PGTRANSACCIONESFACTURAS
SET ESTADOFACTURA = (
        CASE
            WHEN TIPOCANCELACION = 0 THEN 5
            WHEN TIPOCANCELACION = 1 THEN 8
            WHEN TIPOCANCELACION = 2 THEN 7
            WHEN TIPOCANCELACION = 3 THEN 12
            WHEN TIPOCANCELACION = 4 THEN 12
        END
    ),
    NUMEROSEGURIDAD = NUMNUMEROSEGURIDAD,
    FECHAPROCESO = TIMFECHAACTUAL,
    TASACOMPRA = NUMTASADECOMPRA,
    TASAVENTA = NUMTASADEVENTA,
    MONTOCONVERTIDO = DECMONTODEBITOTEMP
WHERE IDUNICOFACTURA = NUMIDUNICOFACTURA
    AND ESTADOFACTURA = 4;
--INSERT INTO SESSION . PGLOGPROCESOTMP ( FECHAINSERCION , NUMEROGRUPO , CODTRANSACCION , MONTODEBITARCTA , SALDOCTADEBITAR , TCCOMPRA , TCVENTA , MENSAJEPROCESO ) 
--VALUES ( CURRENT TIMESTAMP , NUMNUMEROSEGURIDAD , NUMIDUNICOFACTURA , DECMONTODEBITOTEMP , NUMSALDODISPONIBLECUENTA , NUMTASADECOMPRA , NUMTASADEVENTA , 'Despues update factura: ' || COALESCE(INTTIPORESULTADO, '') || ' ' || COALESCE(VARMENSAJERESULTADO, '') || ' ' || COALESCE(CHRPROSEGUIR, '') ) ; 
SET DECMONTODEBITO = DECMONTODEBITO + DECMONTODEBITOTEMP;
SET DECMONTOCREDITO = DECMONTOCREDITO + DECMONTOCREDITOTEMP;
--** Se lleva el conteo de total de facturas aplicadas 
SET INTCONTADORFACTOK = INTCONTADORFACTOK + 1;
SET VARMENSAJERESULTADO = 'APLICADA';
ELSE
UPDATE BLHCYFILES.TB_SE_TRN_PGTRANSACCIONESFACTURAS
SET ESTADOPROCESO = 0,
    ESTADOFACTURA = (
        CASE
            WHEN TIPOCANCELACION = 0 THEN 3
            WHEN TIPOCANCELACION = 2 THEN 7
            WHEN TIPOCANCELACION = 3 THEN 10
            WHEN TIPOCANCELACION = 4 THEN 11
        END
    )
WHERE IDUNICOFACTURA = NUMIDUNICOFACTURA
    AND ESTADOFACTURA = 4;
END IF;
ELSEIF NUMTIPO = 2 THEN IF EXISTS (
    SELECT 1
    FROM BLHCYFILES.DLPMT
    WHERE UNMF10 = NUMIDUNICOFACTURA
) THEN --** Grabar en la tabla temporal del log 
INSERT INTO SESSION.PGLOGPROCESOTMP (
        FECHAINSERCION,
        NUMEROGRUPO,
        CODTRANSACCION,
        MONTODEBITARCTA,
        SALDOCTADEBITAR,
        TCCOMPRA,
        TCVENTA,
        MENSAJEPROCESO
    )
VALUES (
        CURRENT TIMESTAMP,
        NUMNUMEROSEGURIDAD,
        NUMIDUNICOFACTURA,
        DECMONTODEBITOTEMP,
        NUMSALDODISPONIBLECUENTA,
        NUMTASADECOMPRA,
        NUMTASADEVENTA,
        'Cuota pendiente de pago por procesos del cierre'
    );
ELSE --** Se obtiene la fecha y hora actual. 
SELECT TIMESTAMP (
        DATE (
            CAST (CNTRDY + 2000 AS CHAR (4)) || '-' || CNTRDM || '-' || CNTRDD
        ),
        CURRENT TIME
    ) INTO TIMFECHAACTUAL
FROM BLHSRVLIB.A_CNTRLCNT;
UPDATE BLHCYFILES.TB_SE_TRN_PGTRANSACCIONESFACTURAS
SET ESTADOFACTURA = (
        CASE
            WHEN TIPOCANCELACION = 0 THEN 5
            WHEN TIPOCANCELACION = 1 THEN 8
            WHEN TIPOCANCELACION = 2 THEN 7
            WHEN TIPOCANCELACION = 3 THEN 12
            WHEN TIPOCANCELACION = 4 THEN 12
        END
    ),
    NUMEROSEGURIDAD = NUMNUMEROSEGURIDAD,
    FECHAPROCESO = TIMFECHAACTUAL,
    TASACOMPRA = NUMTASADECOMPRA,
    TASAVENTA = NUMTASADEVENTA,
    MONTOCONVERTIDO = DECMONTODEBITOTEMP
WHERE IDUNICOFACTURA = NUMIDUNICOFACTURA
    AND ESTADOFACTURA = 4;
--INSERT INTO SESSION . PGLOGPROCESOTMP ( FECHAINSERCION , NUMEROGRUPO , CODTRANSACCION , MONTODEBITARCTA , SALDOCTADEBITAR , TCCOMPRA , TCVENTA , MENSAJEPROCESO ) 
--VALUES ( CURRENT TIMESTAMP , NUMNUMEROSEGURIDAD , NUMIDUNICOFACTURA , DECMONTODEBITOTEMP , NUMSALDODISPONIBLECUENTA , NUMTASADECOMPRA , NUMTASADEVENTA , 'Cuota pendiente Cancelada, se actualiza estado factura' ) ; 
END IF;
END IF;
ELSE
UPDATE BLHCYFILES.TB_SE_TRN_PGTRANSACCIONESFACTURAS
SET ESTADOPROCESO = 0,
    ESTADOFACTURA = (
        CASE
            WHEN TIPOCANCELACION = 0 THEN 3
            WHEN TIPOCANCELACION = 2 THEN 7
            WHEN TIPOCANCELACION = 3 THEN 10
            WHEN TIPOCANCELACION = 4 THEN 11
        END
    )
WHERE IDUNICOFACTURA = NUMIDUNICOFACTURA
    AND ESTADOFACTURA = 4;
SET VARMENSAJERESULTADO = BLHSRVLIB.FN_SE_SEL_ERROR (LPAD (97, 4, '0'));
END IF;
ELSE
UPDATE BLHCYFILES.TB_SE_TRN_PGTRANSACCIONESFACTURAS
SET ESTADOPROCESO = 0,
    ESTADOFACTURA = (
        CASE
            WHEN TIPOCANCELACION = 0 THEN 3
            WHEN TIPOCANCELACION = 2 THEN 7
            WHEN TIPOCANCELACION = 3 THEN 10
            WHEN TIPOCANCELACION = 4 THEN 11
        END
    )
WHERE IDUNICOFACTURA = NUMIDUNICOFACTURA
    AND ESTADOFACTURA = 4;
END IF;
--** Grabar en la tabla temporal del log 
--INSERT INTO SESSION . PGLOGPROCESOTMP ( FECHAINSERCION , NUMEROGRUPO , CODTRANSACCION , MONTODEBITARCTA , SALDOCTADEBITAR , TCCOMPRA , TCVENTA , MENSAJEPROCESO ) 
--VALUES ( CURRENT TIMESTAMP , NUMNUMEROSEGURIDAD , NUMIDUNICOFACTURA , DECMONTODEBITOTEMP , NUMSALDODISPONIBLECUENTA , NUMTASADECOMPRA , NUMTASADEVENTA , COALESCE(VARMENSAJERESULTADO, '') ) ; 
--** Guardar en la tabla temporal de notificaciones 
--INSERT INTO SESSION . PGCOLANOTIFICACIONESTMP ( FECHAINSERCION , CODTRANSACCION , ESTADO ) 
--VALUES ( CURRENT TIMESTAMP , NUMIDUNICOFACTURA , 0 ) ; 
END FOR FACT_LOOP;
IF DECMONTODEBITO > 0 THEN IF NUMFORMAPAGO_ANT = 3
AND NUMTIPO <> 2 THEN --SET VARDESCRIPCIONDEBITO = SUBSTRING ( TRIM ( VARNOMBREBENEFICIARIO ) || ' ' || CAST ( INTCONTADORFACTOK AS VARCHAR ( 30 ) ) || ' FACTURAS' , 1 , 30 ) ; 
CALL BLHSRVLIB.SP_SE_SEL_NOMBRECIFPAGADOR (
    NUMCIFPAGADOR,
    VARNOMBREPAGADOR,
    INTCODIGOERROR,
    VARMENSAJERESULTADO
);
IF INTCODIGOERROR <> 0
OR TRIM (VARNOMBREPAGADOR) = '' THEN
SET VARNOMBREPAGADOR = 'PAGANET';
END IF;
--SET VARDESCRIPCIONCREDITO = SUBSTRING ( TRIM ( VARNOMBREPAGADOR ) || ' ' || CAST ( INTCONTADORFACTOK AS VARCHAR ( 30 ) ) || ' FACTURAS' , 1 , 30 ) ; 
--SET VARMENSAJERESULTADO = 'CTA PAGADOR: ' || NUMCTAPAGADOR_ANT || ' - CTA BENEFICIARIO: ' || CHRCUENTABENEFICIARIO ; 
--INSERT INTO SESSION . PGLOGPROCESOTMP ( FECHAINSERCION , NUMEROGRUPO , CODTRANSACCION , MONTODEBITARCTA , SALDOCTADEBITAR , TCCOMPRA , TCVENTA , MENSAJEPROCESO ) 
--VALUES ( CURRENT TIMESTAMP , NUMNUMEROSEGURIDAD , 0 , 0 , 0 , 0 , 0 , VARMENSAJERESULTADO ) ; 
--SET VARMENSAJERESULTADO = 'CIF PAGADOR: ' || NUMCIFPAGADOR || ' - CIF BENEFICIARIO: ' || NUMCIFBENEFICIARIO ; 	 
--INSERT INTO SESSION . PGLOGPROCESOTMP ( FECHAINSERCION , NUMEROGRUPO , CODTRANSACCION , MONTODEBITARCTA , SALDOCTADEBITAR , TCCOMPRA , TCVENTA , MENSAJEPROCESO ) 
--VALUES ( CURRENT TIMESTAMP , NUMNUMEROSEGURIDAD , 0 , 0 , 0 , 0 , 0 , COALESCE(VARMENSAJERESULTADO, '') ) ;	 
--PROCESO  STI PAGANET BENEFICIARIO INTERNACIONAL 
SELECT IDUNICOFACTURA,
    MONTOCOMISION,
    MONTOIMPUESTO,
    TASASEGURIDAD,
    DESCRIPCIONCREDITO,
    CORREOSACK1,
    CORREOSACK2,
    DIRECCIONBENEF,
    CIUDADBENEF,
    NOMBREBANCO,
    DIRECCIONBANCO,
    CIUDADBANCO,
    BENEFICIARIOTIPOBANCO,
    BENEFICIARIOBANCO,
    CIUDADBANCOINTERM,
    NOMBBANCOINTERM,
    DIRECBANCOINTERM,
    NUMCUENTABANCOINTERM,
    TIPOBANCOINTERM,
    BANCOINTERM,
    GASTOSCUENTA,
    GASTOSBANCOCORRESPONSAL,
    GLTRANSACCION,
    GLCOMISION,
    GLGASTOSCORRESPONSAL,
    CLIENTID INTO CHRIDUNICOFACTURA,
    NUMMONTOCOMISION,
    NUMMONTOIMPUESTO,
    NUMTASASEGURIDAD,
    CHRDESCRIPCIONCREDITO,
    CHRCORREOSACK1,
    CHRCORREOSACK2,
    CHRDIRECCIONBENEF,
    CHRCIUDADBENEF,
    CHRNOMBREBANCO,
    CHRDIRECCIONBANCO,
    CHRCIUDADBANCO,
    CHRBENEFICIARIOTIPOBANCO,
    CHRBENEFICIARIOBANCO,
    CHRCIUDADBANCOINTERM,
    CHRNOMBBANCOINTERM,
    CHRDIRECBANCOINTERM,
    CHRNUMCUENTABANCOINTERM,
    CHRTIPOBANCOINTERM,
    CHRBANCOINTERM,
    CHRGASTOSCUENTA,
    NUMGASTOSBANCOCORRESPONSAL,
    CHRGLTRANSACCION,
    CHRGLCOMISION,
    CHRGLGASTOSCORRESPONSAL,
    NUMCLIENTID
FROM BLHCYFILES.TB_SE_TRN_PGFACTURASEXTERIOR
WHERE IDUNICOFACTURA = NUMIDUNICOFACTURA_ANT
LIMIT 1;
--MONEDA CUENTA PAGADOR 
SET CHRMONEDACUENTAPAGADOR = (
        SELECT ACMCCY
        FROM BLHCYFILES.ACMST
        WHERE ACMACC = NUMCTAPAGADOR_ANT
        FETCH FIRST 1 ROW ONLY
    );
--TELEFONO CUSPHN 
SELECT CUSNA1,
    CUSPHN,
    CASE
        WHEN CUSLGT = 2 THEN 'NAT'
        ELSE 'JSA'
    END AS LEGALTYPE INTO CHRNOMBREORDENANTE,
    DECTELEFONOPAGADOR,
    CHRTIPOCLIENTE
FROM BLHCYFILES.CUMST
WHERE CUSCUN = NUMCIFPAGADOR;
-- COMMISSIONTYPEID 
-- 1 : PORCENTAJE 
-- 2 : MONTO FIJO 
--CONVERSION CODIGO MONEDA IC 
IF CHRMONEDACUENTAPAGADOR = 'LPS' THEN
SET CHRICMONEDACUENTAPAGADOR = 558;
ELSEIF CHRMONEDACUENTAPAGADOR = 'USD' THEN
SET CHRICMONEDACUENTAPAGADOR = 840;
ELSEIF CHRMONEDACUENTAPAGADOR = 'EUR' THEN
SET CHRICMONEDACUENTAPAGADOR = 978;
END IF;
IF CHRMONEDACTABENEFICIARIO = 'LPS' THEN
SET CHRICMONEDACUENTABENEFICIARIO = 558;
ELSEIF CHRMONEDACTABENEFICIARIO = 'USD' THEN
SET CHRICMONEDACUENTABENEFICIARIO = 840;
ELSEIF CHRMONEDACTABENEFICIARIO = 'EUR' THEN
SET CHRICMONEDACUENTABENEFICIARIO = 978;
END IF;
--VALIDACION TIPO BANCO CORRESPONSAL 
IF CHRTIPOBANCOINTERM = 'D' THEN
SET INTCORRESPONDENTBANKTYPESID = 1;
END IF;
IF CHRTIPOBANCOINTERM = 'A' THEN
SET INTCORRESPONDENTBANKTYPESID = 2;
END IF;
--CALCULOMONTO DEBITO - CREDITO COMISION 
IF (
    SELECT COUNT (*)
    FROM BLHCYFILES.TB_SE_TRN_SITE_COMMISSIONS
    WHERE CLIENTID = NUMCLIENTID
        AND CURRENCYID = CHRICMONEDACUENTAPAGADOR
        AND SUBSIDIARYID = INTSUBSIDIARYID
        AND FEATUREID = INTFEATUREID
) > 0 THEN
SET (
        DECMONTODEBITOCOMISIONTEMP,
        INTTIPOCOMISION,
        NUMMINVALUE,
        NUMMAXVALUE
    ) = (
        SELECT COMMISSIONVALUE,
            COMMISSIONTYPEID,
            MINVALUE,
            MAXVALUE
        FROM BLHCYFILES.TB_SE_TRN_SITE_COMMISSIONS
        WHERE CLIENTID = NUMCLIENTID
            AND CURRENCYID = CHRICMONEDACUENTAPAGADOR
            AND SUBSIDIARYID = INTSUBSIDIARYID
            AND FEATUREID = INTFEATUREID
        FETCH FIRST 1 ROW ONLY
    );
IF INTTIPOCOMISION = 1 THEN
SET DECMONTODEBITOCOMISION = (
        (DECMONTODEBITOCOMISIONTEMP / 100) * DECMONTODEBITO
    );
ELSE
SET DECMONTODEBITOCOMISION = DECMONTODEBITOCOMISIONTEMP;
END IF;
SET (
        DECMONTOCREDITOCOMISIONTEMP,
        INTTIPOCOMISION,
        NUMMINVALUE,
        NUMMAXVALUE
    ) = (
        SELECT COMMISSIONVALUE,
            COMMISSIONTYPEID,
            MINVALUE,
            MAXVALUE
        FROM BLHCYFILES.TB_SE_TRN_SITE_COMMISSIONS
        WHERE CLIENTID = NUMCLIENTID
            AND CURRENCYID = CHRICMONEDACUENTABENEFICIARIO
            AND SUBSIDIARYID = INTSUBSIDIARYID
            AND FEATUREID = INTFEATUREID
        FETCH FIRST 1 ROW ONLY
    );
IF INTTIPOCOMISION = 1 THEN
SET DECMONTOCREDITOCOMISION = (
        (DECMONTOCREDITOCOMISIONTEMP / 100) * DECMONTOCREDITO
    );
ELSE
SET DECMONTOCREDITOCOMISION = DECMONTOCREDITOCOMISIONTEMP;
END IF;
ELSEIF (
    SELECT COUNT (*)
    FROM BLHCYFILES.TB_SE_TRN_GLOBAL_COMMISSIONS
    WHERE SUBSIDIARYID = INTSUBSIDIARYID
        AND CURRENCYID = CHRICMONEDACUENTAPAGADOR
        AND FEATUREID = INTFEATUREID
) > 0 THEN
SET (
        DECMONTODEBITOCOMISIONTEMP,
        INTTIPOCOMISION,
        NUMMINVALUE,
        NUMMAXVALUE
    ) = (
        SELECT COMMISSIONVALUE,
            COMMISSIONTYPEID,
            MINVALUE,
            MAXVALUE
        FROM BLHCYFILES.TB_SE_TRN_GLOBAL_COMMISSIONS
        WHERE SUBSIDIARYID = INTSUBSIDIARYID
            AND CURRENCYID = CHRICMONEDACUENTAPAGADOR
            AND FEATUREID = INTFEATUREID
            AND COMMISSIONVALUE > 0
        FETCH FIRST 1 ROW ONLY
    );
IF INTTIPOCOMISION = 1 THEN
SET DECMONTODEBITOCOMISION = (DECMONTODEBITOCOMISIONTEMP * DECMONTODEBITO);
ELSE
SET DECMONTODEBITOCOMISION = DECMONTODEBITOCOMISIONTEMP;
END IF;
SET (
        DECMONTOCREDITOCOMISIONTEMP,
        INTTIPOCOMISION,
        NUMMINVALUE,
        NUMMAXVALUE
    ) = (
        SELECT COMMISSIONVALUE,
            COMMISSIONTYPEID,
            MINVALUE,
            MAXVALUE
        FROM BLHCYFILES.TB_SE_TRN_GLOBAL_COMMISSIONS
        WHERE SUBSIDIARYID = INTSUBSIDIARYID
            AND CURRENCYID = CHRICMONEDACUENTABENEFICIARIO
            AND FEATUREID = INTFEATUREID
            AND COMMISSIONVALUE > 0
        FETCH FIRST 1 ROW ONLY
    );
IF INTTIPOCOMISION = 1 THEN
SET DECMONTOCREDITOCOMISION = (DECMONTOCREDITOCOMISIONTEMP * DECMONTOCREDITO);
ELSE
SET DECMONTOCREDITOCOMISION = DECMONTOCREDITOCOMISIONTEMP;
END IF;
END IF;
IF INTTIPOCOMISION = 1 THEN IF DECMONTODEBITOCOMISION < NUMMINVALUE THEN
SET DECMONTODEBITOCOMISION = NUMMINVALUE;
ELSEIF DECMONTODEBITOCOMISION > NUMMAXVALUE THEN
SET DECMONTODEBITOCOMISION = NUMMAXVALUE;
END IF;
IF DECMONTOCREDITOCOMISION < NUMMINVALUE THEN
SET DECMONTOCREDITOCOMISION = NUMMINVALUE;
ELSEIF DECMONTOCREDITOCOMISION > NUMMAXVALUE THEN
SET DECMONTOCREDITOCOMISION = NUMMAXVALUE;
END IF;
END IF;
--CALCULO MONTO DEBITO - CREDITO GASTO CORRESPONSAL 
IF (
    SELECT COUNT (*)
    FROM BLHCYFILES.TB_SE_TRN_SITECORRESPONDENTBANKEXPENSES
    WHERE CURRENCYID = CHRICMONEDACUENTAPAGADOR
        AND SUBSIDIARYID = INTSUBSIDIARYID
        AND CLIENTID = NUMCLIENTID
        AND CORRESPONDENTBANKTYPESID = INTCORRESPONDENTBANKTYPESID
) > 0 THEN
SET DECMONTODEBITOGASTOCORRESPONSAL = (
        SELECT CHARGEAMOUNT
        FROM BLHCYFILES.TB_SE_TRN_SITECORRESPONDENTBANKEXPENSES
        WHERE CURRENCYID = CHRICMONEDACUENTAPAGADOR
            AND SUBSIDIARYID = INTSUBSIDIARYID
            AND CLIENTID = NUMCLIENTID
            AND CORRESPONDENTBANKTYPESID = INTCORRESPONDENTBANKTYPESID
        FETCH FIRST 1 ROW ONLY
    );
SET DECMONTOCREDITOGASTOCORRESPONSAL = (
        SELECT CHARGEAMOUNT
        FROM BLHCYFILES.TB_SE_TRN_SITECORRESPONDENTBANKEXPENSES
        WHERE CURRENCYID = CHRICMONEDACUENTABENEFICIARIO
            AND SUBSIDIARYID = INTSUBSIDIARYID
            AND CLIENTID = NUMCLIENTID
            AND CORRESPONDENTBANKTYPESID = INTCORRESPONDENTBANKTYPESID
        FETCH FIRST 1 ROW ONLY
    );
ELSEIF (
    SELECT COUNT (*)
    FROM BLHCYFILES.TB_SE_TRN_GLOBALCORRESPONDENTBANKEXPENSES
    WHERE CURRENCYID = CHRICMONEDACUENTAPAGADOR
        AND SUBSIDIARYID = INTSUBSIDIARYID
        AND CORRESPONDENTBANKTYPESID = INTCORRESPONDENTBANKTYPESID
) > 0 THEN
SET DECMONTODEBITOGASTOCORRESPONSAL = (
        SELECT CHARGEAMOUNT
        FROM BLHCYFILES.TB_SE_TRN_GLOBALCORRESPONDENTBANKEXPENSES
        WHERE CURRENCYID = CHRICMONEDACUENTAPAGADOR
            AND SUBSIDIARYID = INTSUBSIDIARYID
            AND CORRESPONDENTBANKTYPESID = INTCORRESPONDENTBANKTYPESID
        FETCH FIRST 1 ROW ONLY
    );
SET DECMONTOCREDITOGASTOCORRESPONSAL = (
        SELECT CHARGEAMOUNT
        FROM BLHCYFILES.TB_SE_TRN_GLOBALCORRESPONDENTBANKEXPENSES
        WHERE CURRENCYID = CHRICMONEDACUENTABENEFICIARIO
            AND SUBSIDIARYID = INTSUBSIDIARYID
            AND CORRESPONDENTBANKTYPESID = INTCORRESPONDENTBANKTYPESID
        FETCH FIRST 1 ROW ONLY
    );
END IF;
CALL BLHSRVLIB.SP_SE_VAR_TRANSFERENCIAEXTERIOR (
    NUMCIFPAGADOR,
    CHRIDUNICOFACTURA,
    NUMCTAPAGADOR_ANT,
    CHRGLTRANSACCION,
    CHRMONEDACUENTAPAGADOR,
    CHRCUENTABENEFICIARIO,
    CHRMONEDACTABENEFICIARIO,
    VARNOMBREBENEFICIARIO,
    CHRDIRECCIONBENEF,
    CHRCIUDADBENEF,
    CHRBENEFICIARIOTIPOBANCO,
    CHRBENEFICIARIOBANCO,
    CHRNOMBREBANCO,
    CHRDIRECCIONBANCO,
    CHRCIUDADBANCO,
    DECMONTODEBITO,
    DECMONTODEBITO,
    CHRDESCRIPCIONCREDITO,
    CHRGASTOSCUENTA,
    CHRNOMBREORDENANTE,
    CHRDOCUMENTOIDENTIDADBENEFICIARIO,
    DECTELEFONOPAGADOR,
    CHRCORREOSACK1,
    CHRCORREOSACK2,
    DECTCUSDCOMPRA,
    DECTCUSDVENTA,
    NUMGASTOSBANCOCORRESPONSAL,
    NUMMONTOCOMISION,
    NUMTASASEGURIDAD,
    CHRTIPOBANCOINTERM,
    CHRBANCOINTERM,
    CHRNOMBBANCOINTERM,
    CHRDIRECBANCOINTERM,
    CHRCIUDADBANCOINTERM,
    CHRCIUDADBANCOINTERM,
    CHRNUMCUENTABANCOINTERM,
    VARNUMEROREFERENCIA,
    INTTIPORESULTADO,
    VARMENSAJERESULTADO
);
IF INTTIPORESULTADO <> 0 THEN
SET INTTIPORESULTADO = INTTIPORESULTADO;
SET VARMENSAJERESULTADO = VARMENSAJERESULTADO;
SIGNAL SQLSTATE '75000'
SET MESSAGE_TEXT = VARMENSAJERESULTADO;
END IF;
